Basic filter usage
```tsx
import { ComboBox } from '@commercetools/nimbus';

function MyComponent() {
return (
<ComboBox.Root
items={items}
filter={ComboBox.filters.filterByStartsWith}
>
<ComboBox.Trigger />
<ComboBox.Popover>
<ComboBox.ListBox>
 {(item) => <ComboBox.Option>{item.name}</ComboBox.Option>}
</ComboBox.ListBox>
</ComboBox.Popover>
</ComboBox.Root>
);
}
```
Multi-property search
```tsx
const productFilter = ComboBox.filters.createMultiPropertyFilter<Product>([
'name',
'category',
'description'
]);

function ProductSearch() {
return (
<ComboBox.Root items={products} filter={productFilter}>
<ComboBox.Trigger />
<ComboBox.Popover>
<ComboBox.ListBox>
 {(item) => <ComboBox.Option>{item.name}</ComboBox.Option>}
</ComboBox.ListBox>
</ComboBox.Popover>
</ComboBox.Root>
);
}
```
Section-aware filtering
```tsx
const sectionFilter = ComboBox.filters.createSectionAwareFilter(
ComboBox.filters.filterByFuzzy
);

function SectionedSearch() {
return (
<ComboBox.Root items={sectionsWithItems} filter={sectionFilter}>
<ComboBox.Trigger />
<ComboBox.Popover>
<ComboBox.ListBox>
 {(section) => (
   <ComboBox.Section>
     {(item) => <ComboBox.Option>{item.name}</ComboBox.Option>}
   </ComboBox.Section>
 )}
</ComboBox.ListBox>
</ComboBox.Popover>
</ComboBox.Root>
);
}
```
